import{_ as a,o as t,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"GTM Web Setup","description":"","frontmatter":{"title":"GTM Web Setup","slug":"gtm-web"},"headers":[],"relativePath":"developer-hub/gtm-web.md","filePath":"developer-hub/gtm-web.md"}'),i={name:"developer-hub/gtm-web.md"};function r(o,e,l,p,c,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>You can use Google Tag Manager (GTM) to trigger specific actions related to Branch.</p><p>This guide walks you how to do this for your web app, in combination with the Branch Web SDK.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to use GTM and Branch together, you first need to:</p><ol><li>Create a Google Tag Manager account that has a container with &quot;Web&quot; as the chosen platform.</li><li><a href="./web-basic-integration.html">Integrate</a> the Branch Web SDK into your web app.</li></ol><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="install-google-tag-manager" tabindex="-1">Install Google Tag Manager <a class="header-anchor" href="#install-google-tag-manager" aria-label="Permalink to &quot;Install Google Tag Manager&quot;">​</a></h3><ol><li><p>Navigate to the <strong>Admin</strong> tab.</p></li><li><p>In the section with container details, select <strong>Install Google Tag Manager</strong>.</p></li><li><p>You will be taken to a screen with two code snippets; follow GTM&#39;s instructions for adding the code snippets to your HTML files.</p></li><li><p><strong>Optional</strong>: you can also set metadata that you want to have included with tracked events. To do this, place the script containing the metadata <strong>before</strong> the GTM script in your <code>&lt;head&gt;</code> tag. An example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>   window.dataLayer = window.dataLayer || [];</span></span>
<span class="line"><span>   window.dataLayer.push({</span></span>
<span class="line"><span>   	&#39;customerID&#39;: &#39;customer-id-guid&#39;,</span></span>
<span class="line"><span>   	&#39;event&#39;: &#39;playVideo&#39;,</span></span>
<span class="line"><span>   	&#39;videoId&#39;: &#39;vid-000-123&#39;,</span></span>
<span class="line"><span>   	&#39;videoFormat&#39;: &#39;hd&#39;</span></span>
<span class="line"><span>   });</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div></li></ol><h3 id="initialize-branch-sdk" tabindex="-1">Initialize Branch SDK <a class="header-anchor" href="#initialize-branch-sdk" aria-label="Permalink to &quot;Initialize Branch SDK&quot;">​</a></h3><ol><li>Go to the <strong>Workspace</strong> tab, then navigate to <strong>Tags</strong>.</li><li>Click <strong>New</strong> and set the tag type as &quot;Custom HTML&quot;.</li><li>Paste your Branch Web SDK <a href="./web-basic-integration.html#2-install-branch">script snippet</a> into the HTML box. Make sure to also <a href="./web-basic-integration.html#3-initialize-branch">initialize</a> Branch.</li><li>Set <strong>Tag firing options</strong> to &quot;Once per page&quot;.</li><li>Scroll down to the <strong>Triggering</strong> section to choose a trigger to associate with the tag.</li><li>Select the &quot;All Pages&quot; trigger with type &quot;Page View&quot;. If you only want the Branch Web SDK to initialize on certain pages, select &quot;Some Pages&quot; instead.</li></ol><h2 id="implement-branch-features" tabindex="-1">Implement Branch Features <a class="header-anchor" href="#implement-branch-features" aria-label="Permalink to &quot;Implement Branch Features&quot;">​</a></h2><h3 id="track-events" tabindex="-1">Track Events <a class="header-anchor" href="#track-events" aria-label="Permalink to &quot;Track Events&quot;">​</a></h3><p>To track events with Branch using GTM, you will need to create user-defined variables, a trigger, and a tag.</p><h4 id="_1-create-variables" tabindex="-1">1. Create Variables <a class="header-anchor" href="#_1-create-variables" aria-label="Permalink to &quot;1. Create Variables&quot;">​</a></h4><p>Create a new user-defined variable that will describe the event you are logging.</p><ol><li><p>In the <strong>Workspace</strong> tab, click on <strong>Variables</strong>.</p></li><li><p>In the <strong>User-Defined Variables</strong> section, click <strong>New</strong>.</p></li><li><p>For variable type, select &quot;Data Layer Variable&quot;.</p></li><li><p>Give the variable a name that correlates to the name of the metadata property you want to log alongside the event.</p></li><li><p>Repeat this process to create a new user-defined variable for each metadata property you want to include in the event.</p><p>For example, if you have the following metadata structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>   window.dataLayer = window.dataLayer || [];</span></span>
<span class="line"><span>   window.dataLayer.push({</span></span>
<span class="line"><span>     &#39;customerID&#39;: &#39;customer-id-guid&#39;,</span></span>
<span class="line"><span>     &#39;event&#39;: &#39;playVideo&#39;,</span></span>
<span class="line"><span>     &#39;videoId&#39;: &#39;vid-000-123&#39;,</span></span>
<span class="line"><span>     &#39;videoFormat&#39;: &#39;hd&#39;</span></span>
<span class="line"><span>   });</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div><p>You might have the following user-defined variables:</p></li></ol><h4 id="_2-create-a-trigger" tabindex="-1">2. Create A Trigger <a class="header-anchor" href="#_2-create-a-trigger" aria-label="Permalink to &quot;2. Create A Trigger&quot;">​</a></h4><p>Create a new trigger that will define when you want to log an event.</p><ol><li>In the <strong>Workspace</strong> tab, click on <strong>Triggers</strong>.</li><li>Click <strong>New</strong>, and create a trigger with type <strong>Custom Event</strong>.</li><li>Provide an event name and configure when you want the trigger to fire.</li><li>Click <strong>Save</strong>.</li></ol><h4 id="_3-create-a-tag" tabindex="-1">3. Create A Tag <a class="header-anchor" href="#_3-create-a-tag" aria-label="Permalink to &quot;3. Create A Tag&quot;">​</a></h4><p>Create a new tag, which will describe what you want to have occur when a trigger fires.</p><ol><li><p>In the <strong>Workspace</strong> tab, click on <strong>Tags</strong>.</p></li><li><p>Click <strong>New</strong>, and create a tag with type &quot;Custom HTML&quot;.</p></li><li><p>Paste a script into the HTML box that sends variable data to Branch. This is done via the Web SDK&#39;s <code>logEvent()</code> <a href="./web-full-reference.html">method</a>.</p><p>If your variable data in GTM looks like this:</p><p>Then your script will look like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>	var data = {</span></span>
<span class="line"><span>		event: {{Event Name}},</span></span>
<span class="line"><span>		videoFormat: {{videoFormat}},</span></span>
<span class="line"><span>		videoId: {{videoId}}</span></span>
<span class="line"><span>	};</span></span>
<span class="line"><span>	branch.logEvent(&quot;custom_event&quot;, data, function(err) { </span></span>
<span class="line"><span>		console.log(err); </span></span>
<span class="line"><span>	});</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div></li><li><p>In the <strong>Triggering</strong> section, associate the trigger you created in step 2 with this tag you are creating.</p></li><li><p>Click <strong>Save</strong>.</p></li></ol><h3 id="set-user-identities" tabindex="-1">Set User Identities <a class="header-anchor" href="#set-user-identities" aria-label="Permalink to &quot;Set User Identities&quot;">​</a></h3><p>To set user identities, you will need to make changes in both GTM and your HTML files.</p><h4 id="_1-create-identity-variable" tabindex="-1">1. Create Identity Variable <a class="header-anchor" href="#_1-create-identity-variable" aria-label="Permalink to &quot;1. Create Identity Variable&quot;">​</a></h4><p>Create a variable that will correlate to the user identity metadata property.</p><ol><li>In the <strong>Workspace</strong> tab, click on <strong>Variables</strong>.</li><li>In the <strong>User-Defined Variables</strong> section, click <strong>New</strong>.</li><li>For variable type, select &quot;Data Layer Variable&quot;.</li><li>Give the variable a name, such as <code>customerID</code>.</li><li>Click <strong>Save</strong>.</li></ol><h4 id="_2-create-trigger" tabindex="-1">2. Create Trigger <a class="header-anchor" href="#_2-create-trigger" aria-label="Permalink to &quot;2. Create Trigger&quot;">​</a></h4><p>Create a trigger and configure it to fire when you want an ID set.</p><ol><li>In the <strong>Workspace</strong> tab, click on <strong>Triggers</strong>.</li><li>Click <strong>New</strong>, and select the trigger type you want to use. This will likely be &quot;Page View&quot; or &quot;Custom Event&quot;.</li><li>Give the trigger an event name, and configure when you want it to fire.</li><li>Click <strong>Save</strong>.</li></ol><h4 id="_3-create-tag-to-set-id" tabindex="-1">3. Create Tag to Set ID <a class="header-anchor" href="#_3-create-tag-to-set-id" aria-label="Permalink to &quot;3. Create Tag to Set ID&quot;">​</a></h4><p>Create a tag that will invoke the Branch Web SDK&#39;s <code>setIdentity()</code> <a href="./web-full-reference.html#setidentity">method</a> when your triggered is fired.</p><ol><li><p>In the <strong>Workspace</strong> tab, click on <strong>Tags</strong>.</p></li><li><p>Click <strong>New</strong>, and create a tag with type &quot;Custom HTML&quot;.</p></li><li><p>Paste a script into the HTML box that uses the <code>setIdentity()</code> method. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>	var data = { </span></span>
<span class="line"><span>		customerID: {{customerID}}</span></span>
<span class="line"><span>	};</span></span>
<span class="line"><span>	branch.setIdentity(data.customerID);</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div></li><li><p>In the <strong>Triggering</strong> section, associate the trigger you created in step 2 with this tag you are creating.</p></li></ol><h4 id="_4-set-metadata-in-html" tabindex="-1">4. Set Metadata in HTML <a class="header-anchor" href="#_4-set-metadata-in-html" aria-label="Permalink to &quot;4. Set Metadata in HTML&quot;">​</a></h4><p>Make sure you are setting the user identity in the data layer so GTM can read it. Do this <strong>before</strong> the GTM script in your <code>&lt;head&gt;</code> tag.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script&gt;</span></span>
<span class="line"><span>   window.dataLayer = window.dataLayer || [];</span></span>
<span class="line"><span>   window.dataLayer.push({</span></span>
<span class="line"><span>   	&#39;customerID&#39;: &#39;customer-id-guid&#39;</span></span>
<span class="line"><span>   });</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>To make sure you&#39;ve successfully set up GTM to work with the Branch Web SDK:</p><ol><li>Trigger the event you are interested in, based on the trigger you set up in GTM.</li><li>Go to the Liveview <a href="https://dashboard.branch.io/liveview/events" target="_blank" rel="noreferrer">page</a> of the Branch Dashboard.</li><li>Filter the dropdown to the relevant event type that you are interested in, such as &quot;custom event&quot;.</li><li>Check to make sure that the event is being triggered with the expected details.</li></ol><p>Note that when a user&#39;s identity is set, you will see a network call to Branch&#39;s <code>v1/profile</code> endpoint.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><p>Visit our <a href="./google-tag-manager.html#faqs">FAQs section</a> to learn more about implementing Branch with GTM.</p>`,43)])])}const u=a(i,[["render",r]]);export{d as __pageData,u as default};
